@ARTICLE{10.1002/jsfa.70301,
	author = {Feng Z and Yong W and Zhang R and Li M and Pang M and Zhang X and Wei Y and Sun G},
	title = {Corn peptides alleviate high-fat diet-induced obesity and metabolic disorders in mice by regulating adipogenesis and intestinal microbial disorders.},
	journal = {J Sci Food Agric},
	year = {2026},
	abstract = {BACKGROUND: Corn peptides (CPs) are natural bioactive peptides with multiple beneficial effects. A previous study found that CPs enhanced endurance by activating the AMPK/PGC-1α signaling pathway and increasing intestinal probiotics involved in lipid metabolism, leading to the hypothesis that CPs may have anti-obesity effects. RESULTS: The current study established an obesity model by feeding mice a high-fat diet (HFD) for 8 weeks, followed by CPs for 4 weeks. The results show that CPs effectively decreased bodyweight, epididymal fat weight, and liver fat accumulation in obese mice. They also show that CPs administration reduced lipid levels and metabolic disorders and ameliorated liver steatosis in HFD-fed obese mice. Corn peptides significantly increased the expression levels of PPARγ and PGC-1α proteins in subcutaneous inguinal white adipose tissue (iWAT), while those of SREBP1 and FAS were decreased. Corn proteins also increased the abundance of intestinal probiotic bacteria and reduced the harmful bacteria count, which may contribute to their anti-obesity effects. The Kyoto Encyclopedia of Genes and Genomes database revealed significant differences in genes that were differentially expressed in response to treatment with CPs. Genes associated with various transporters, including ATP-binding cassette transporters, and with lipid metabolism were enriched. Those related to amino acid metabolism, oxidative phosphorylation, insulin resistance, and atherosclerosis were downregulated. There were also significant changes in genes involved in carbohydrate metabolism. CONCLUSIONS: Corn proteins can alleviate HFD-induced weight gain and related metabolic disorders by regulating lipid adipogenesis and intestinal microecology. © 2025 Society of Chemical Industry.},
	doi = {10.1002/jsfa.70301},
	pmid = {41255063 [Indexed for MEDLINE]}
}

@ARTICLE{10.1021/acs.jafc.5c10351,
	author = {Koh YC and Kamchonemenukool S and Ho PY and Weerawatanakorn M and Pan MH},
	title = {Oleic Acid-Esterified Octacosanol as a Functional Ingredient to Counter Obesity-Associated Lipid Dysregulation through PPAR-Targeted Regulation.},
	journal = {J Agric Food Chem},
	year = {2026},
	abstract = {Octacosanol, a major constituent of policosanol, exhibits lipid-lowering activity, particularly when esterified with fatty acids. Although its cholesterol-lowering actions have been linked to the modulation of fatty acid and cholesterol biosynthesis, its functions within adipose tissue remain poorly defined. Here, we examined nonesterified octacosanol (NO), lauric acid-esterified octacosanol (LEO), and oleic acid-esterified octacosanol (OEO) in high-fat diet-fed mice for 11 weeks. Target prediction and molecular docking identified PPARα and PPARδ as putative targets of octacosanol, guiding downstream mechanistic analyses in adipose tissue. Both NO and OEO enhanced lipolysis; NO preferentially increased fatty acid β-oxidation, whereas OEO specifically promoted thermogenic remodeling, indicating distinct metabolic consequences driven by ester chemistry. Together, these findings demonstrate that structural modification, particularly oleic acid esterification, substantially augments the metabolic activity of octacosanol in lipid catabolism and thermogenesis, underscoring its potential relevance in obesity-associated metabolic regulation.},
	doi = {10.1021/acs.jafc.5c10351},
	pmid = {41254832 [Indexed for MEDLINE]},
	note = {PMC12862754}
}

@ARTICLE{10.1016/j.psj.2025.106104,
	author = {Gao M and Han Q and Zhu Q and Li D and Li X and Lv Z and Guo Y},
	title = {Maternal effects of choline on skeletal muscle development and intramuscular fat deposition in broiler offspring.},
	abstract = {Low-protein diets with low inclusion of soybean meal have been used in breeder hens and not affected the laying performance, however, it's usually observed the detrimental effects on skeletal muscle growth and intramuscular fat deposition in the offspring. One of the major reasons is the reduced supply of choline when the dietary inclusion of soybean meal is limited. Choline is an essential methyl donor and a critical regulator of lipid metabolism. The underlying mechanisms through which maternal chloride supplementation affects offspring muscle growth and lipid metabolism remain largely unclear. This study aimed to clarify the maternal effect of choline on regulating embryonic and post-hatch skeletal muscle development and intramuscular fat deposition in broiler offspring. Maternal choline chloride (CC) supplementation improved egg weight, Haugh unit, and shell strength, and increased yolk S-adenosylmethionine concentration (P < 0.01). It also elevated phosphatidylcholine (PC) levels in serum and yolk of hens and in the serum of newly hatched chicks (P < 0.05). Enhanced embryonic breast muscle fiber formation and higher half-eviscerated yield at 42 d of age were observed in the CC group (P < 0.05). Maternal choline increased lipid droplet accumulation in the liver and breast muscle of embryos at day 19. In cultured chicken myotubes, choline chloride upregulated the expression of SLC16A7 and FASN and increased intracellular malonyl-CoA and triglyceride (TG) contents (P < 0.01). At 42 d, maternal choline supplementation enhanced TG deposition in the breast muscle by activating SLC16A7 and FASN-mediated fatty acid synthesis. Targeted metabolomics further revealed elevated concentrations of myristic and palmitic acids in the offspring muscle (P < 0.01). Collectively, maternal choline supplementation improved egg quality and yolk PC deposition in breeder hens and promoted muscle growth and intramuscular fat accumulation in the offspring. These findings provide a new insight into the significance of the trans-generational effects of choline nutrition for optimizing broiler breeder diets and improving meat quality of the offspring.},
	doi = {10.1016/j.psj.2025.106104},
	pmid = {41252858 [Indexed for MEDLINE]},
	note = {PMC12666344}
}

@ARTICLE{10.1002/cbdv.202502019,
	author = {Xiao C and Zhou P and Luo L and Zhang Q and Zhang Y and Tan L and Fu M and Quan W and Tang Y and Zhou L and Wu K and Deng L},
	title = {Chinese Yam Polysaccharide Ameliorates Obesity by Promoting Lipolysis Via the cAMP/PKA Signaling Pathway.},
	journal = {Chem Biodivers},
	year = {2026},
	abstract = {Obesity is associated with multiple health problems and has become a major public health challenge worldwide. In this study, the monosaccharide composition of CYP was determined using the PMP pre-column derivatization method. The results showed that CYP was composed of Glc, Gal, Ara, Man, and GlcA. In addition, the anti-obesity effects of CYP were evaluated using OP9 cells in vitro and a zebrafish obesity model in vivo. The findings revealed that CYP effectively promoted lipolysis, significantly modulated the expression of lipolysis-related proteins, and markedly reduced lipid accumulation in obese zebrafish. Subsequently, the potential molecular mechanism underlying the anti-obesity effects of CYP was explored via network pharmacology, molecular docking, and experimental validation. Protein-protein interaction network analysis identified five core targets, including STAT3, CASP3, PPARA, JUN, and MMP9. Moreover, KEGG enrichment analysis and molecular docking indicated that the cAMP signaling pathway may mediate the anti-obesity effects of CYP, with STAT3 serving as a potential therapeutic target. Furthermore, Western blot experiments demonstrated that CYP downregulated STAT3 expression and activated the cAMP/PKA signaling pathway, thereby ameliorating obesity. Collectively, these findings suggest that CYP holds promise as a novel anti-obesity agent.},
	doi = {10.1002/cbdv.202502019},
	pmid = {41240330 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/advs.202417330,
	author = {Wang H and Yang C and Luo D and Liu P and Zeng Z and Peng W and Peng D and Su H and Xiao X and Wang H and Jin X},
	title = {Obesity-Associated TRIM15 Promotes the Proliferation of Esophageal Adenocarcinoma Through the YY2/FOXRED1 Axis.},
	journal = {Adv Sci (Weinh)},
	year = {2026},
	abstract = {Obesity has been identified as an independent risk factor for gastroesophageal reflux disease (GERD) and esophageal adenocarcinoma (EAC). Oxidative stress and inflammation driven by chronic GERD are the main causes of the tumorigenesis of EAC, but the underlying mechanism remains elusive. Here, the inflammation-upregulated E3 ligase, tripartite motif 15 (TRIM15), is identified as a key driver of obesity-associated EAC. TRIM15 promotes the degradation of YY2 is demonstrated through the ubiquitin-proteasome system, which in turn dysregulates lipid metabolism and enhances the proliferation of EAC cells. Furthermore, YY2 transcriptionally is shown that increases FOXRED1 expression. FOXRED1 is subsequently identified as an essential effector for the TRIM15-induced dysregulation of lipid and energy metabolism in EAC cells. Thus, a novel obesity-associated TRIM15/YY2/FOXRED1 axis is identified that contributes to the proliferation of EAC. Given that lipid metabolism regulates ferroptosis by controlling cellular processes associated with phospholipid peroxidation. The TRIM15/YY2/FOXRED1 axis demonstrates that it modulates SLC3A2 expression via the mTOR/c-MYC pathway, thereby regulating GPX4 levels to influence EAC sensitivity to ferroptosis-inducing compounds and proposing a therapeutic strategy for EAC.},
	doi = {10.1002/advs.202417330},
	pmid = {41237333 [Indexed for MEDLINE]},
	note = {PMC12822407}
}

@ARTICLE{10.1038/s41366-025-01945-9,
	author = {Shi Y and Cao M and Wang K and Qi G and Dong F and Zhang X},
	title = {The role of SIRT4 in obesity: from molecular mechanisms to clinical implications.},
	journal = {Int J Obes (Lond)},
	year = {2026},
	abstract = {Obesity has emerged as a pervasive global public health issue, and the etiology of obesity is now understood to be increasingly intricate and multifactorial, encompassing genetic predispositions, sedentary lifestyles coupled with excessive caloric intake, as well as environmental and social interactions. Recent studies have indicated a close association between SIRT4 and obesity. The pathophysiological mechanisms underlying its influence on obesity predominantly involve four interconnected pathways: fatty acid oxidation, adipocyte differentiation, insulin secretion, and inflammation. Furthermore, emerging studies are exploring the clinical translational potential of SIRT4. As a mitochondria-localized member of the sirtuin family, SIRT4 possesses both deacetylase and ADP-ribosyltransferase enzymatic activities. This mitochondrial enzyme is involved in metabolic regulation through modulating energy homeostasis and lipid metabolic processes, inflammatory signaling pathways, neuroendocrine regulatory networks, and the epigenetics of adipocyte differentiation. However, the lack of comprehensive synthesis and critical evaluation of existing evidence has left the precise relationship between SIRT4 and obesity incompletely understood. Therefore, this review systematically synthesizes current knowledge regarding SIRT4's mechanistic involvement in obesity development, while evaluating clinical correlations and regulatory strategies. This review focuses on the potential of SIRT4 in the regulation of obesity and the progress in related studies. The search criteria encompass keywords related to the role of SIRT4 in physiological and biochemical processes such as lipid and energy metabolism, adipocyte differentiation, as well as its clinical applications, with a total of 63 references cited.},
	doi = {10.1038/s41366-025-01945-9},
	pmid = {41233560 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.envres.2025.123297,
	author = {Jiang N and Chen Q and Cheng B and Meng K and Wang J and Li T and Chen H and Liao Y and Sun H and Liu R},
	title = {Associations of urinary environmental phenols with obesity and lipid metabolism in children and adolescents: The expanded Chinese National Human Biomonitoring (CNHBM) project.},
	journal = {Environ Res},
	year = {2026},
	abstract = {Despite ubiquitous exposure to environmental phenols (EPs), their associations with obesity are poorly understood due to inconsistent findings and inadequate mechanistic insights. Within the China National Human Biomonitoring program, we measured 15 urinary EPs in 860 children/adolescents from Jiangsu Province, employing lipidomics to investigate obesity associations. EPs were detectable in 17.93 %-96.79 % samples, with Bisphenol B (BPB) and benzophenone-4 (BP-4) emerging as predominant compounds. Urinary EPs concentrations correlated significantly with sex, BMI status, household income, and dietary patterns. Multivariable logistic regression showed a linear inverse association between BPB and BP-4 exposure and overweight/obesity in pubertal girls. Bayesian Kernel Machine Regression (BKMR) and Quantile g-computation (QGC) analyses confirmed that urinary EPs were inversely associated with overweight/obesity in the overall cohort (OR = 0.76, 95 % CI: 0.59-0.98) and among girls (OR = 0.63, 95 % CI: 0.44-0.90). Lipidome-wide association studies (LWAS) applied generalized linear models (GLMs) with Gaussian and binomial distributions to evaluate the relationships of EP concentrations and overweight/obesity status with lipid abundances, identifying 28 metabolites and 10 pathways that link EPs exposure to overweight/obesity. Mediation analyses indicated BP-4 effects were partially mediated by glycerophospholipid (-6 % to -13 %) and sphingolipid metabolites (9 %-18 %), whereas BPB effects were driven by sphingolipid (7 %-8 %). Stratified analyses indicate that alterations in glycerophospholipid and sphingolipid pathways mediate sex-specific EPs effects on overweight and obesity, providing a theoretical basis for targeted public health strategies.},
	doi = {10.1016/j.envres.2025.123297},
	pmid = {41232908 [Indexed for MEDLINE]}
}

@ARTICLE{10.2337/db25-0295,
	author = {Wang C and Hou Y and Zhang M and Wang J and Chu X and Liang M and Sun C and Xie J and Zhang J and Wang CY},
	title = {miR-432 Exacerbates Obesity-Induced Dysregulation of Glucose and Lipid Homeostasis.},
	journal = {Diabetes},
	year = {2026},
	abstract = {miRNAs are key regulators of metabolic homeostasis, yet their role in obesity-associated dysfunction remains incompletely understood. Here, we identify miR-432 as a driver of systemic metabolic dysregulation. Serum miRNA profiling revealed a positive correlation between miR-432 expression and obesity/type 2 diabetes mellitus. Functionally, adipose-specific miR-432 exacerbated high-fat diet-induced obesity and insulin resistance. Similarly, hepatic-specific miR-432 aggravated hepatic steatosis and systemic glucose dysregulation, while skeletal muscle-specific miR-432 disrupted glucose homeostasis without affecting body composition. Mechanistically, miR-432 disrupted insulin sensitivity by inhibiting the PIK3R3/AKT pathway and perturbed lipid homeostasis by suppressing the PIK3R3/PPAR-α axis. Notably, obesity-induced miR-432 upregulation was predominantly localized in adipocytes and driven by the CDK5/PPAR-γ axis. Furthermore, adipocyte-derived exosomal miR-432 was identified as a mediator of systemic metabolic dysfunction, facilitating intertissue cross talk in obesity. Collectively, our data demonstrate that miR-432 exacerbates obesity-induced dysregulation of glucose and lipid metabolism. ARTICLE HIGHLIGHTS: miR-432 overexpression in adipose tissue, liver, and skeletal muscle exacerbates high-fat diet-induced disruption of metabolic homeostasis. miR-432 impairs glucose homeostasis by suppressing the PIK3R3/AKT pathway and disrupts lipid homeostasis via inhibition of the PIK3R3/PPAR-α axis or directly suppressing PPAR-α. Obesity-induced elevation of miR-432 is predominantly localized in adipocytes and driven by the CDK5/PPAR-γ axis. Adipocyte-derived exosomal miR-432 mediates systemic metabolic dysfunction, establishing an intertissue regulatory network.},
	doi = {10.2337/db25-0295},
	pmid = {41218910 [Indexed for MEDLINE]},
	note = {PMC12716619}
}

@ARTICLE{10.1016/j.micres.2025.128393,
	author = {Zheng C and Xie J and Tang F and Wang Z and Liu L and Pi Y and Zhong Y and He Z and Liu T and Zheng J and Luo J},
	title = {Bacteroides acidifaciens alleviates high-fat diet-induced obesity-related osteoporosis by regulating gut microbiota and bile acid metabolism via the gut-bone axis.},
	journal = {Microbiol Res},
	year = {2026},
	abstract = {Obesity disrupts bone formation-resorption balance. Despite the established role of Bacteroides acidifaciens (B. acidifaciens) in modulating metabolic homeostasis, reducing inflammation, and improving lipid metabolism, its impact on obesity-associated osteoporosis is still not well understood. In this study, we delved into the potential protective influence of B. acidifaciens on high-fat diet (HFD) induced bone loss. The results showed that B. acidifaciens sharply improved weight gain, glucose and lipid metabolism in 16 weeks HFD mice. Both In vitro and in vivo experiments have conclusively demonstrated that the introduction of B. acidifaciens notably ameliorated the imbalance of HFD induced osteogenesis and osteoclastogenesis. B. acidifaciens also regulated HFD induced gut microbiota and bile acid metabolism, and strengthened intestinal mucosal barrier function. Additionally, B. acidifaciens significantly activated the AMPK-PPARα signaling pathway in bone tissue. Thus, our study indicated that B. acidifaciens regulated metabolism, restored gut microbiota balance, and activated AMPK-PPARα pathway to prevent HFD-induced bone loss, potentially aiding in preventing and treating obesity-related osteoporosis.},
	doi = {10.1016/j.micres.2025.128393},
	pmid = {41205303 [Indexed for MEDLINE]}
}

@ARTICLE{10.1038/s41386-025-02273-2,
	author = {Liu C and Li Z and Ji JJ and Liu K and Samsom JN and Li T and Lu Q and Liu F},
	title = {Single-cell RNA sequencing uncovers molecular features underlying microglial lipid accumulation and depression-related behaviors in high-fat diet mouse model of obesity.},
	journal = {Neuropsychopharmacology},
	year = {2026},
	abstract = {Obesity is a worldwide health crisis, with unhealthy diet as a major contributor. Comorbid neuropsychiatric conditions such as depression and anxiety are associated with obesity. Since obesity is a pro-inflammatory state, chronic neuroinflammation may mediate obesity and neuropsychiatric comorbidity. We used RNA-seq to provide a single-cell resolution transcriptome of brain immune cells using long-term high-fat diet (HFD) to model obesity in male mice. HFD mice exhibited depression and anxiety-like behavior. We observed a shift towards increased proportions of lipid droplet-accumulating microglia (LDAM) in the long-term HFD brain. By in-depth characterization of the transcriptional signature of LDAM, we identified that ACSL1, a key regulator of lipid droplet biogenesis, was highly expressed in LDAM induced by HFD. Finally, we demonstrated that ACSL1 inhibition reduced lipid droplets deposition in microglia exposed to free fatty acids (FFA). Our findings provide a comprehensive view of the molecular changes in brain immune cells associated with HFD, suggesting a link between microglial lipid droplet accumulation and neurological comorbidities induced by obesity.},
	doi = {10.1038/s41386-025-02273-2},
	pmid = {41198848 [Indexed for MEDLINE]},
	note = {PMC12824154}
}
